  ('social-worker-moex-07572', 'social-worker', 'social-worker-moex-099-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '在所謂共依（codependency）的主要觀念中，下列那一項敘述不正確？', '["當事人會將自我價值建立在外在參考標準上", "當事人會過度維護別人的福利，因而忽略自己的需求", "當事人易產生罪惡感或過度焦慮", "當事人的行為模式不屬於病態行為"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "ed6ad7e1f554", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07573', 'social-worker', 'social-worker-moex-099-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據Lemkau與Olson（1988）的看法，女性對墮胎問題的行為處理，下列敘述何者不正確？', '["多數女性墮胎後會有罪惡感及心情沮喪", "女性墮胎若是出於自願則比較不會後悔", "多數女性墮胎後會產生心理問題", "若未進行墮胎，子女出生後的問題可能更多"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "ed6ad7e1f554", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07574', 'social-worker', 'social-worker-moex-099-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據擴充理論（enrichment theory）的觀點，下列陳述那一項不正確？', '["個人感官所接收的資訊是完整且具體的", "個人需將相關資訊予以聯結並賦予意義", "個人既有的認知期待會幫助自己擴充視覺經驗", "知覺可以協助個人詮釋感官所提供的訊息"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:38+00:00", "source_pdf_sha1": "ed6ad7e1f554", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "099010", "c": "902", "s": "600", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "099", "exam_name": "099年第一次醫事人員、中醫師、營養師、心理師、語言治療師、醫師分試、社會工作師", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
